<?php echo view("grupo_donato_gestao\\Views\\components\\finance_nav", ["active" => "generate"]); ?>
<div class="card"><div class="page-title"><h1><?php echo app_lang('gd_finance_generate_month'); ?></h1></div><div class="card-body"><?php echo form_open(get_uri('grupo_donato/finance/generate/confirm'),['id'=>'generation-form','class'=>'general-form']); ?><div class="row"><div class="col-md-4"><input type="month" id="reference-month" name="reference_month" class="form-control" value="<?php echo date('Y-m'); ?>"></div><div class="col-md-3"><button type="button" id="preview-generation" class="btn btn-default"><?php echo app_lang('gd_finance_preview'); ?></button></div></div><div id="generation-preview" class="mt-4"></div><button id="confirm-generation" type="submit" class="btn btn-primary hide"><?php echo app_lang('gd_finance_confirm_generation'); ?></button><?php echo form_close(); ?></div></div><script>$(document).ready(function(){"use strict";$("#preview-generation").click(function(){$.post('<?php echo_uri('grupo_donato/finance/generate/preview'); ?>',{reference_month:$("#reference-month").val()},function(r){if(!r.success)return appAlert.error(r.message);var h='<table class="table"><tr><th><?php echo app_lang('gd_finance_customer'); ?></th><th><?php echo app_lang('gd_finance_description'); ?></th><th><?php echo app_lang('gd_finance_due'); ?></th><th><?php echo app_lang('gd_finance_amount'); ?></th></tr>';$.each(r.data,function(_,x){h+='<tr><td>'+x.customer_name+'</td><td>'+x.description+'</td><td><input type="date" class="form-control" name="adjustments['+x.key+'][due_date]" value="'+x.due_date+'"></td><td><input class="form-control" name="adjustments['+x.key+'][amount]" value="'+(x.amount||'')+'"></td></tr>';});$("#generation-preview").html(h+'</table>');$("#confirm-generation").removeClass('hide');},'json');});$("#generation-form").appForm({onSuccess:function(r){appAlert.success(r.message);}});});</script>
